{
  "summary": "This paper proposes leveraging automated unit tests to filter pseudo-labeled data for unsupervised code translation, significantly improving semantic accuracy by selecting translations that pass translated unit tests. The approach uses EvoSuite-generated Java tests translated to Python and C++, enabling offline and online self-training methods that outperform prior unsupervised models on a large parallel dataset of 135,000 functions.",
  "strengths": [
    {
      "point": "Innovative use of automated unit tests as semantic filters to improve unsupervised code translation.",
      "evidence": "The method filters candidate translations by running translated unit tests, ensuring semantic equivalence and reducing noise from back-translation."
    },
    {
      "point": "Comprehensive experimental validation with large-scale datasets and ablation studies.",
      "evidence": "Experiments on 135,000 functions across Java, Python, and C++ show up to 24% absolute improvement in CA@1 and detailed ablations on cache usage, mutation score thresholds, and beam search."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent semantic-aware code translation methods leveraging ASTs or program graphs.",
      "evidence": "The paper compares mainly against TransCoder and DOBF but omits baselines like GraphCodeBERT or TreeTrans that explicitly model program semantics."
    },
    {
      "point": "Insufficient justification and validation for translating unit tests from Java to other languages instead of generating native tests.",
      "evidence": "No ablation or analysis is provided to assess the impact of translating Java unit tests to Python and C++ rather than generating tests directly in target languages."
    },
    {
      "point": "Evaluation relies heavily on CA@N without reporting standard metrics like BLEU or CodeBLEU.",
      "evidence": "The paper omits traditional metrics that would contextualize semantic accuracy gains relative to surface-level fluency or syntactic similarity."
    },
    {
      "point": "Reproducibility concerns due to missing detailed descriptions of unit test translation, training hyperparameters, and cache mechanism.",
      "evidence": "Key procedural details and hyperparameters are not fully specified, limiting reproducibility and understanding of critical components."
    },
    {
      "point": "Limited discussion on scalability, robustness to flaky or incomplete tests, and handling of language-specific idioms or APIs.",
      "evidence": "The method is evaluated on isolated functions with generated tests, without addressing challenges in large, interdependent codebases or real-world noisy test scenarios."
    }
  ],
  "questions": [
    {
      "question": "How does the method compare empirically to semantic-aware models that incorporate AST or graph representations?",
      "motivation": "Benchmarking against these baselines is necessary to clarify the novelty and relative benefits of unit test filtering."
    },
    {
      "question": "What is the impact of generating unit tests natively in target languages versus translating Java tests on filtering effectiveness and translation quality?",
      "motivation": "Understanding this would validate the key methodological choice and its effect on semantic coverage and correctness."
    },
    {
      "question": "How robust is the approach to noisy, incomplete, or flaky unit tests common in real-world projects?",
      "motivation": "Robustness to imperfect tests is critical for practical deployment and generalization beyond controlled datasets."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
